# Prompt: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

from flask import Flask, request, send_file
import os
import subprocess
import tempfile
import boto3

app = Flask(__name__)
s3 = boto3.client('s3')

@app.route('/screenshot', methods=['POST'])
def screenshot():
    url = request.json.get('url')
    if not url:
        return "URL is required", 400

    with tempfile.TemporaryDirectory() as tmp_dir:
        cmd = f'chromium-browser --headless --disable-gpu --noerrdialogs --print-to-pdf={tmp_dir}/screenshot.pdf {url}'
        subprocess.run(cmd, shell=True)

        with open(f'{tmp_dir}/screenshot.pdf', 'rb') as f:
            thumbnail = f.read()

        s3.put_object(Body=thumbnail, Key='screenshots/' + url.split('/')[-1] + '.pdf', Bucket='your-bucket-name')

    return send_file(f'{tmp_dir}/screenshot.pdf', as_attachment=True)

if __name__ == '__main__':
    app.run()